import './MenuItem.scss';

import { Icon } from ':components/Icon';
import { useMenuContext } from ':components/Menu/MenuContext';
import { SubMenu } from ':components/Menu/SubMenu';
import { Typography } from ':components/Typography';
import { useDeviceSize } from ':helpers';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont';
import React, { useEffect, useRef, useState } from 'react';

import type { MenuItemProps } from './MenuItem.types';

export const MenuItem: React.FC<MenuItemProps> = ({
	title,
	iconName,
	subtitle,
	disabled,
	children,
	onClick,
	className,
	isOpen,
	onMouseEnter,
	onMouseLeave,
	internalPosition,
	id = '-1',
}) => {
	const itemRef = useRef(null);
	const [isSubMenuOpen, setIsSubMenuOpen] = useState(false);
	const closeMenuTimeout = useRef(null);
	const openMenuTimeout = useRef(null);

	const { focusedId, setFocusedId, ids, addId } = useMenuContext();
	const { isExtraSmallDevice } = useDeviceSize();

	useEffect(() => {
		if (!ids.includes(id) && !disabled) {
			addId(id);
		}
	}, [ids]);

	useEffect(() => {
		if (id !== '0') {
			return;
		}
		setFocusedId('');
	}, [isOpen]);

	useEffect(() => {
		if (focusedId.slice(0, id.length) !== id) {
			setIsSubMenuOpen(false);
		}
		if (focusedId !== id) {
			return;
		}
		!disabled && setIsSubMenuOpen(true);
		const handleKeyDown = event => {
			if (event.key === 'Enter') {
				event.preventDefault();
				onClick?.();
			}
		};
		globalThis.addEventListener('keydown', handleKeyDown);

		return () => {
			globalThis.removeEventListener('keydown', handleKeyDown);
		};
	}, [focusedId, id]);

	const closeMenu = () => {
		onMouseLeave?.();
		if (openMenuTimeout.current) {
			clearTimeout(openMenuTimeout.current);
		}
		closeMenuTimeout.current = setTimeout(() => {
			setIsSubMenuOpen(false);
		}, 300);
	};

	const openMenu = () => {
		onMouseEnter?.();
		if (disabled) {
			return;
		}
		if (closeMenuTimeout.current) {
			clearTimeout(closeMenuTimeout?.current);
		}
		openMenuTimeout.current = setTimeout(() => {
			setIsSubMenuOpen(true);
		}, 300);
	};

	const shouldRenderChildren = children && !isExtraSmallDevice;

	if (children && isExtraSmallDevice) {
		console.warn('[dsb-menu] В мобильной версии компонента Menu вложенность недоступна!');
	}

	return (
		<li onMouseLeave={closeMenu} className={className} role="menuitem">
			<div
				ref={itemRef}
				className={classNames('menuitem', disabled && 'menuitem-disabled', focusedId === id && 'menuitem-focused')}
				onClick={disabled ? () => null : onClick}
				onMouseOver={openMenu}
				onMouseLeave={closeMenu}
			>
				{iconName && <Icon className="menuitem__icon" iconName={iconName} />}
				<Typography className="menuitem__title" variant="body2">
					{title}
				</Typography>

				<div className="menuitem__right">
					{subtitle && (
						<Typography className="menuitem__right__subtitle" variant="body2">
							{subtitle}
						</Typography>
					)}
					{shouldRenderChildren && <Icon className="menuitem__right__expand" iconName={Icons.NavArrowRight} />}
				</div>
			</div>
			{shouldRenderChildren && (
				<div onMouseEnter={openMenu}>
					<SubMenu
						internalPosition={internalPosition}
						className={classNames('menuitem__cascade')}
						parent={itemRef}
						isOpen={isOpen === undefined ? isSubMenuOpen : isOpen}
						id={id}
					>
						{children}
					</SubMenu>
				</div>
			)}
		</li>
	);
};

MenuItem.displayName = 'MenuItem';
